using System;using System.Collections.Generic;class A{static void Main(){var p=Console.ReadLine().Split(' ');int L=int.Parse(p[0]),C=int.Parse(p[1]),N=int.Parse(p[2]);int[]g=new int[N];for(int i=0;i<N;i++)g[i]=int.Parse(Console.ReadLine());long t=0;int r=0,h=0;var m=new Dictionary<int,(int,long)>();while(r<C){if(m.ContainsKey(h)){var(pr,pt)=m[h];int cl=r-pr;long ce=t-pt,q=(C-r)/cl;t+=q*ce;r+=(int)(q*cl);break;}m[h]=(r,t);int c=L,j=h;long e=0;for(int i=0;i<N&&g[j]<=c;i++){c-=g[j];e+=g[j];j=(j+1)%N;}t+=e;r++;h=j;}while(r<C){int c=L,j=h;long e=0;for(int i=0;i<N&&g[j]<=c;i++){c-=g[j];e+=g[j];j=(j+1)%N;}t+=e;r++;h=j;}Console.Write(t);}}